INSERT INTO `hasil_ujian` VALUES (32,10,'20102010','Razzib','XII XII',0,NULL,'2026-04-28 08:23:51','[{\"soal_id\":69,\"pertanyaan\":\"Konektor yang umum digunakan pada kabel UTP untuk jaringan komputer adalah...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"RJ-11\",\"opsi_b\":\"RJ-45\",\"opsi_c\":\"BNC\",\"opsi_d\":\"USB\",\"opsi_e\":\"HDMI\"},{\"soal_id\":70,\"pertanyaan\":\"Urutan warna standar T568B untuk kabel UTP dimulai dengan warna...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Hijau Putih\",\"opsi_b\":\"Cokelat Putih\",\"opsi_c\":\"Oranye Putih\",\"opsi_d\":\"Biru Putih\",\"opsi_e\":\"Oranye\"},{\"soal_id\":71,\"pertanyaan\":\"Jenis kabel UTP yang digunakan untuk menghubungkan dua perangkat yang sama (misal komputer ke komputer) secara langsung adalah...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Straight-through\",\"opsi_b\":\"Rollover\",\"opsi_c\":\"Crossover\",\"opsi_d\":\"Fiber Optic\",\"opsi_e\":\"Coaxial\"},{\"soal_id\":72,\"pertanyaan\":\"Alat yang digunakan untuk memotong dan menjepit konektor RJ-45 pada kabel UTP disebut...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"a\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Crimping Tool\",\"opsi_b\":\"Tang Kombinasi\",\"opsi_c\":\"Obeng\",\"opsi_d\":\"Solder\",\"opsi_e\":\"LAN Tester\"},{\"soal_id\":73,\"pertanyaan\":\"Untuk menguji apakah kabel UTP yang telah dikrimping berfungsi dengan baik, alat yang digunakan adalah...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Multimeter\",\"opsi_b\":\"Oscilloscope\",\"opsi_c\":\"LAN Tester\",\"opsi_d\":\"Router\",\"opsi_e\":\"Switch\"},{\"soal_id\":74,\"pertanyaan\":\"Alamat unik dalam bentuk angka yang digunakan untuk mengidentifikasi perangkat di jaringan disebut...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"MAC Address\",\"opsi_b\":\"IP Address\",\"opsi_c\":\"Home Address\",\"opsi_d\":\"URL\",\"opsi_e\":\"Email\"},{\"soal_id\":75,\"pertanyaan\":\"Subnet mask default yang umum digunakan untuk jaringan kelas C adalah...\",\"jawaban_siswa\":\"a\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"255.0.0.0\",\"opsi_b\":\"255.255.0.0\",\"opsi_c\":\"255.255.255.0\",\"opsi_d\":\"255.255.255.255\",\"opsi_e\":\"192.168.1.1\"},{\"soal_id\":76,\"pertanyaan\":\"Perintah pada command prompt yang digunakan untuk mengecek konektivitas antar dua perangkat adalah...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"ipconfig\",\"opsi_b\":\"getmac\",\"opsi_c\":\"ping\",\"opsi_d\":\"tracert\",\"opsi_e\":\"cls\"},{\"soal_id\":77,\"pertanyaan\":\"IP Address 192.168.1.10 termasuk ke dalam kategori alamat...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"a\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Privat\",\"opsi_b\":\"Publik\",\"opsi_c\":\"Global\",\"opsi_d\":\"Multicast\",\"opsi_e\":\"Broadcast\"},{\"soal_id\":78,\"pertanyaan\":\"Jika sebuah komputer tidak bisa terhubung ke internet padahal kabel sudah terpasang, langkah awal troubleshooting adalah...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Membeli komputer baru\",\"opsi_b\":\"Mengecek IP Address\",\"opsi_c\":\"Memutus kabel listrik\",\"opsi_d\":\"Menghapus semua data\",\"opsi_e\":\"Mengganti casing\"},{\"soal_id\":79,\"pertanyaan\":\"Fungsi utama dari \'Default Gateway\' dalam konfigurasi jaringan adalah...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Menyimpan data\",\"opsi_b\":\"Menghubungkan jaringan lokal ke jaringan luar\",\"opsi_c\":\"Mempercepat prosesor\",\"opsi_d\":\"Mencetak dokumen\",\"opsi_e\":\"Mematikan komputer\"},{\"soal_id\":80,\"pertanyaan\":\"Gejala \'Request Timed Out\' (RTO) saat melakukan ping biasanya menunjukkan...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Koneksi sangat cepat\",\"opsi_b\":\"Koneksi terputus atau tidak sampai ke tujuan\",\"opsi_c\":\"Warna kabel salah\",\"opsi_d\":\"Hardisk penuh\",\"opsi_e\":\"Monitor rusak\"},{\"soal_id\":81,\"pertanyaan\":\"Kabel UTP kategori 5e (Cat5e) mampu mendukung kecepatan transmisi data hingga...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"10 Mbps\",\"opsi_b\":\"100 Mbps\",\"opsi_c\":\"1000 Mbps (1 Gbps)\",\"opsi_d\":\"10 Gbps\",\"opsi_e\":\"100 Gbps\"},{\"soal_id\":82,\"pertanyaan\":\"Susunan kabel UTP yang digunakan untuk menghubungkan komputer ke Switch\\/Hub adalah...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"a\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Straight-through\",\"opsi_b\":\"Crossover\",\"opsi_c\":\"Spiral\",\"opsi_d\":\"Circle\",\"opsi_e\":\"Random\"},{\"soal_id\":83,\"pertanyaan\":\"Perintah \'ipconfig\' pada sistem operasi Windows berfungsi untuk...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Mengirim pesan teks\",\"opsi_b\":\"Mengetahui konfigurasi IP Address perangkat\",\"opsi_c\":\"Membuka browser\",\"opsi_d\":\"Menghapus virus\",\"opsi_e\":\"Memformat disk\"},{\"soal_id\":84,\"pertanyaan\":\"Apa tujuan utama dari keamanan jaringan komputer?\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Menambah kecepatan internet\",\"opsi_b\":\"Melindungi data dari akses yang tidak sah\",\"opsi_c\":\"Memperindah tampilan desktop\",\"opsi_d\":\"Memperbanyak jumlah koneksi\",\"opsi_e\":\"Menghapus data lama\"},{\"soal_id\":85,\"pertanyaan\":\"Aspek keamanan yang memastikan bahwa data hanya dapat diakses oleh orang yang berwenang disebut...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Integrity\",\"opsi_b\":\"Availability\",\"opsi_c\":\"Confidentiality\",\"opsi_d\":\"Authentication\",\"opsi_e\":\"Non-repudiation\"},{\"soal_id\":86,\"pertanyaan\":\"Manakah yang termasuk faktor ancaman keamanan jaringan dari sisi manusia?\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Bencana alam\",\"opsi_b\":\"Kerusakan kabel\",\"opsi_c\":\"Serangan malware (hacking\\/cracking)\",\"opsi_d\":\"Suhu ruangan panas\",\"opsi_e\":\"Petir\"},{\"soal_id\":87,\"pertanyaan\":\"Aspek \'Integrity\' dalam keamanan data berarti...\",\"jawaban_siswa\":\"a\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Data harus selalu tersedia\",\"opsi_b\":\"Data tidak boleh diubah oleh pihak yang tidak berwenang\",\"opsi_c\":\"Data harus bisa dicetak\",\"opsi_d\":\"Data harus berukuran kecil\",\"opsi_e\":\"Data harus disimpan di cloud\"},{\"soal_id\":88,\"pertanyaan\":\"Perangkat lunak atau perangkat keras yang berfungsi menyaring lalu lintas data di jaringan disebut...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Router\",\"opsi_b\":\"Switch\",\"opsi_c\":\"Firewall\",\"opsi_d\":\"Hub\",\"opsi_e\":\"Access Point\"},{\"soal_id\":89,\"pertanyaan\":\"Salah satu cara paling dasar untuk mengamankan akun pengguna di jaringan adalah menggunakan...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Nama asli\",\"opsi_b\":\"Foto profil\",\"opsi_c\":\"Password yang kuat dan unik\",\"opsi_d\":\"Status online\",\"opsi_e\":\"Alamat rumah\"},{\"soal_id\":90,\"pertanyaan\":\"Proses mengubah data menjadi kode rahasia agar tidak mudah dibaca disebut...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Kompresi\",\"opsi_b\":\"Ekstraksi\",\"opsi_c\":\"Enkripsi\",\"opsi_d\":\"Deskripsi\",\"opsi_e\":\"Transmisi\"},{\"soal_id\":91,\"pertanyaan\":\"Ancaman keamanan berupa program yang dapat menggandakan diri dan merusak sistem disebut...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Spam\",\"opsi_b\":\"Virus\",\"opsi_c\":\"Hardware\",\"opsi_d\":\"Software\",\"opsi_e\":\"Freeware\"},{\"soal_id\":92,\"pertanyaan\":\"Tindakan memalsukan identitas untuk mendapatkan informasi sensitif seperti username\\/password disebut...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"a\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Phishing\",\"opsi_b\":\"Chatting\",\"opsi_c\":\"Browsing\",\"opsi_d\":\"Streaming\",\"opsi_e\":\"Uploading\"},{\"soal_id\":93,\"pertanyaan\":\"Mengapa kita harus melakukan update sistem operasi secara berkala untuk keamanan?\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Agar tampilan selalu baru\",\"opsi_b\":\"Untuk menutup celah keamanan (vulnerability)\",\"opsi_c\":\"Untuk menghapus semua file\",\"opsi_d\":\"Agar hardisk penuh\",\"opsi_e\":\"Hanya untuk menghabiskan kuota\"},{\"soal_id\":94,\"pertanyaan\":\"Proses memverifikasi identitas pengguna (seperti login) saat akan masuk ke sistem disebut...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Otorisasi\",\"opsi_b\":\"Autentikasi\",\"opsi_c\":\"Audit\",\"opsi_d\":\"Akuntansi\",\"opsi_e\":\"Instalasi\"},{\"soal_id\":95,\"pertanyaan\":\"Aspek \'Availability\' dalam keamanan jaringan menjamin bahwa...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Data rahasia aman\",\"opsi_b\":\"Data tidak berubah\",\"opsi_c\":\"Layanan jaringan tersedia saat dibutuhkan pengguna\",\"opsi_d\":\"Data terenkripsi\",\"opsi_e\":\"Data bisa dihapus siapa saja\"},{\"soal_id\":96,\"pertanyaan\":\"Dalam konfigurasi Wi-Fi, protokol keamanan yang umum digunakan saat ini adalah...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"WEP\",\"opsi_b\":\"WPA2 atau WPA3\",\"opsi_c\":\"HTTP\",\"opsi_d\":\"FTP\",\"opsi_e\":\"SMTP\"},{\"soal_id\":97,\"pertanyaan\":\"Apa risiko utama jika kita menggunakan jaringan Wi-Fi publik yang tidak terenkripsi?\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Sinyal menjadi lebih kuat\",\"opsi_b\":\"Data pribadi mudah disadap atau dicuri\",\"opsi_c\":\"Baterai HP awet\",\"opsi_d\":\"Internet menjadi gratis selamanya\",\"opsi_e\":\"Laptop menjadi lebih cepat\"},{\"soal_id\":98,\"pertanyaan\":\"Tindakan pencegahan untuk menjaga ketersediaan data jika terjadi kerusakan sistem atau serangan adalah...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Formatting\",\"opsi_b\":\"Deleting\",\"opsi_c\":\"Melakukan Backup data\",\"opsi_d\":\"Editing\",\"opsi_e\":\"Copying\"}]',NULL,NULL,0,NULL),(33,9,'20102010','Arkanza','I',0,NULL,'2026-04-28 08:30:20','[{\"soal_id\":39,\"pertanyaan\":\"Apa nama topologi yang menghubungkan semua komputer ke satu titik pusat (hub\\/switch)?\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"b\",\"is_correct\":false,\"poin\":10,\"poin_diperoleh\":0,\"opsi_a\":\"Topologi Bus\",\"opsi_b\":\"Topologi Star\",\"opsi_c\":\"Topologi Ring\",\"opsi_d\":\"Topologi Mesh\",\"opsi_e\":\"Topologi Tree\"},{\"soal_id\":40,\"pertanyaan\":\"Topologi jaringan yang menggunakan satu kabel tunggal sebagai media transmisi utama disebut...\",\"jawaban_siswa\":\"e\",\"kunci_jawaban\":\"c\",\"is_correct\":false,\"poin\":10,\"poin_dipe